import{_ as a,o as n,c as i,a2 as p}from"./chunks/framework.C24VBsJ9.js";const d=JSON.parse('{"title":"GPIO 按键驱动","description":"","frontmatter":{"title":"GPIO 按键驱动"},"headers":[],"relativePath":"tutorial/driver/05_gpio_key_driver/01_introduction.md","filePath":"tutorial/driver/05_gpio_key_driver/01_introduction.md","lastUpdated":1781369075000}'),l={name:"tutorial/driver/05_gpio_key_driver/01_introduction.md"};function e(t,s,r,h,c,o){return n(),i("div",null,[...s[0]||(s[0]=[p(`<h1 id="gpio-按键驱动-我们终于要从输出走向输入了" tabindex="-1">GPIO 按键驱动 - 我们终于要从输出走向输入了 <a class="header-anchor" href="#gpio-按键驱动-我们终于要从输出走向输入了" aria-label="Permalink to &quot;GPIO 按键驱动 - 我们终于要从输出走向输入了&quot;">​</a></h1><p>前面几章我们都在折腾输出设备——LED、蜂鸣器，这些有个共同点：CPU 控制它们，想让它们干嘛就干嘛。说干就干，写个寄存器，LED 就亮了；再写一次，蜂鸣器就叫了。这种掌控感确实让人上瘾。</p><p>但现实世界不全是输出设备。我们还需要处理输入设备——按键、传感器、触摸屏，这些设备不听 CPU 的指挥，反过来是它们告诉 CPU 发生了什么。这种角色的转换一开始让人有点不适应，我承认刚开始学的时候确实折腾了好几天。</p><h2 id="输入和输出的本质区别" tabindex="-1">输入和输出的本质区别 <a class="header-anchor" href="#输入和输出的本质区别" aria-label="Permalink to &quot;输入和输出的本质区别&quot;">​</a></h2><p>输出设备和输入设备的区别说起来简单，但理解透彻不容易：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 输出设备：CPU 写 GPIO */</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">writel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(GPIO_DR, val);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // LED 亮了</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* 输入设备：CPU 读 GPIO */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">u32 val </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> readl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(GPIO_DR);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 按键状态</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>区别就在这一读一写。输出是 CPU 主动的，输入是 CPU 被动的。输出什么时候发生由代码决定，输入什么时候发生由用户决定（用户什么时候按键谁知道）。</p><p>这个&quot;谁说了算&quot;的问题，直接影响了驱动的设计。</p><h2 id="按键驱动要解决的问题" tabindex="-1">按键驱动要解决的问题 <a class="header-anchor" href="#按键驱动要解决的问题" aria-label="Permalink to &quot;按键驱动要解决的问题&quot;">​</a></h2><p>说实话，第一次写按键驱动的时候，我以为很简单。不就是读个 GPIO 吗？能有多复杂。结果现实给了我一记响亮的耳光，坑真的不少。</p><p>第一个问题是：<strong>怎么知道按键被按下了？</strong></p><p>你说我读 GPIO 状态吧，什么时候读？一直读？那 CPU 不就空转了吗？间隔着读？那按键刚好在两次读取之间按下怎么办？</p><p>第二个问题是：<strong>按键会抖动</strong></p><div class="warning custom-block"><p class="custom-block-title">这是一个真实的坑</p><p>机械按键的触点在接触瞬间会抖动。你按一下，GPIO 电平可能会跳变好几次：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>理想波形（以为）：</span></span>
<span class="line"><span>    ┌───────────────────</span></span>
<span class="line"><span>────┘                   └─────</span></span>
<span class="line"><span></span></span>
<span class="line"><span>实际波形（真实）：</span></span>
<span class="line"><span>    ┌─┬───┬─────┬────────</span></span>
<span class="line"><span>────┘ │   │     │        └──</span></span>
<span class="line"><span>    └─┘   └─┬─┬─┘</span></span>
<span class="line"><span>             └─┘</span></span>
<span class="line"><span>    ←──── 5-50ms ────→</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>我第一次测试驱动的时候，按一下按键，应用程序居然收到好多次事件。查了半天才发现是这个抖动问题。真的，这种硬件特性只有踩过坑才会印象深刻。</p></div><p>第三个问题是：<strong>CPU 占用的问题</strong></p><p>如果你用轮询方式——就是不停地读 GPIO 状态——CPU 占用率会很高。这不像 LED，设置一下就完事了，按键驱动需要持续监控。</p><h2 id="我们先学轮询方式" tabindex="-1">我们先学轮询方式 <a class="header-anchor" href="#我们先学轮询方式" aria-label="Permalink to &quot;我们先学轮询方式&quot;">​</a></h2><p>这些问题的终极解决方案是用中断。但中断有自己的复杂度，需要理解中断系统、中断处理函数、下半部机制这些概念。</p><p>所以我们决定分两步走：先学轮询方式，再学中断方式。</p><p>轮询方式虽然效率低，但有几个好处：</p><div class="tip custom-block"><p class="custom-block-title">轮询方式的教学价值</p><ol><li><strong>简单直接</strong>——代码逻辑一目了然，没有隐藏的魔法</li><li><strong>容易调试</strong>——出问题了直接看循环里的状态就行</li><li><strong>建立概念</strong>——先理解&quot;等待事件&quot;的概念，再学中断会轻松很多</li></ol><p>说实话，我觉得如果一开始就学中断，很容易迷失在各种机制里。先跑通轮询，建立信心，再学中断，这条路更平滑。</p></div><h2 id="按键的硬件连接" tabindex="-1">按键的硬件连接 <a class="header-anchor" href="#按键的硬件连接" aria-label="Permalink to &quot;按键的硬件连接&quot;">​</a></h2><p>我们的 Alpha 开发板上有一个按键，连接方式是经典的低电平触发：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>     +3.3V</span></span>
<span class="line"><span>       |</span></span>
<span class="line"><span>       &lt;</span></span>
<span class="line"><span>       &gt; 10kΩ 上拉电阻</span></span>
<span class="line"><span>       &lt;</span></span>
<span class="line"><span>       |</span></span>
<span class="line"><span>       +---- GPIO1_IO18</span></span>
<span class="line"><span>       |</span></span>
<span class="line"><span>    按键开关</span></span>
<span class="line"><span>       |</span></span>
<span class="line"><span>      GND</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><p>这个电路的工作原理：</p><ul><li>按键松开时，上拉电阻把 GPIO 拉到高电平（3.3V）</li><li>按键按下时，开关导通，GPIO 被拉到地（0V）</li></ul><div class="info custom-block"><p class="custom-block-title">为什么用上拉而不是下拉？</p><p>这是个设计选择问题。上拉的好处是功耗低——按键松开时几乎没有电流。下拉的话，按键按下时会有电流从 VCC 流到 GND。对于电池供电的设备，这个差异可能很重要。</p><p>另外，很多传统设计习惯用上拉，可能历史原因多一些。</p></div><h2 id="设备树配置" tabindex="-1">设备树配置 <a class="header-anchor" href="#设备树配置" aria-label="Permalink to &quot;设备树配置&quot;">​</a></h2><p>设备树里这样描述这个按键：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">imxaes_key_gpio: key</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gpio {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    compatible </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;imxaes-key-gpio&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    pinctrl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">names </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;default&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    pinctrl</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">pinctrl_key</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    gpios </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gpio1 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">18</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GPIO_ACTIVE_LOW</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    status </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;okay&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">};</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这里的 <code>GPIO_ACTIVE_LOW</code> 很关键。它告诉内核：这个按键是低电平触发的。当按键按下时，GPIO 物理上是低电平，但逻辑上应该解释为&quot;按键按下&quot;（1）。</p><p>这个反转逻辑在驱动层会自动处理，我们写代码的时候不用管。</p><h2 id="本章教程的结构" tabindex="-1">本章教程的结构 <a class="header-anchor" href="#本章教程的结构" aria-label="Permalink to &quot;本章教程的结构&quot;">​</a></h2><p>为了把这个主题讲清楚，我们把内容拆成了几个小节：</p><ol><li><strong>GPIO 输入机制</strong>——怎么配置 GPIO 为输入，怎么读取状态</li><li><strong>轮询实现</strong>——在 <code>read()</code> 函数里循环等待按键事件</li><li><strong>抖动现象</strong>——为什么按键会抖，轮询方式怎么处理</li><li><strong>编译测试</strong>——跑起来看看真实效果</li></ol><p>每一节都比较短，可以慢慢消化。说实话，输入设备确实比输出设备复杂一点，但一步一步来，没什么搞不定的。</p><h2 id="为什么值得学这个" tabindex="-1">为什么值得学这个 <a class="header-anchor" href="#为什么值得学这个" aria-label="Permalink to &quot;为什么值得学这个&quot;">​</a></h2><p>你可能会问：现在都有现成的按键驱动框架（<code>gpio-keys</code>），为什么还要自己从头写？</p><div class="tip custom-block"><p class="custom-block-title">学习价值大于实用价值</p><p>确实，实际工程里你会直接用 <code>gpio-keys</code> 这个通用驱动，配置好设备树就行了。但自己写一遍轮询驱动，你会理解：</p><ul><li>GPIO 输入的底层机制</li><li>轮询方式的工作原理和局限性</li><li>为什么需要中断机制</li></ul><p>有了这些理解，以后遇到更复杂的输入设备——触摸屏、加速度计——你就知道从哪里下手了。</p></div><p>好了，背景介绍差不多了。下一节我们开始看代码，先从 GPIO 输入的机制说起。</p><hr><p><strong>下一章</strong>: <a href="./02_gpio_input_mechanism">GPIO 输入机制</a></p>`,42)])])}const u=a(l,[["render",e]]);export{d as __pageData,u as default};
